mapper.select:
SELECT DISTINCT t.*
FROM task t

    INNER JOIN task_tag tt ON t.id = tt.task_id AND tt.tag_id IN

        #{tagId}




        AND (t.title LIKE CONCAT('%', #{q.keyword}, '%') OR t.description LIKE CONCAT('%', #{q.keyword}, '%'))


        AND t.type = #{q.type}


        AND t.budget_max >= #{q.budgetMin}


        AND t.budget_min <= #{q.budgetMax}


        AND t.status = #{q.status}


        AND t.status = 2


ORDER BY t.created_at DESC
